module top  (
	input wire clk1,
	input wire clk2,
	input wire rst,
	input wire sel,
	input wire d_1,
	input wire d_2,
	input wire d_3,
	output reg q_1,
	output reg q_2
);
wire mux_to_ff1, mux_to_ff2;
fd32 inst1_fd32(
	.d_1(d_1),
	.clk(clk2),
	.clr(mux_to_ff1),//违反
	.q_1(q_1) 
);
fd32 inst2_fd32(
	.d_1(d_1),
	.clk(mux_to_ff2),//违反
	.clr(rst),
	.q_1(q_2) 
);
fd31 inst1_fd31(
	.a_1 (clk1),
	.b_1 (d_3),
	.sl_1(sel),
	.q_1 (mux_to_ff1)
	);   
fd31 inst2_fd31(
	.a_1 (clk1),
	.b_1 (d_2),
	.sl_1(sel),
	.q_1 (mux_to_ff2)
	);   	
endmodule


module fd31(
	input wire a_1,
	input wire b_1,
	input wire sl_1,
	output reg  q_1
);
always@(sl_1 or a_1 or b_1)
	begin
		if(!sl) q_1 = a_1;
		else q_1 = b_1;
	end 
endmodule

