module fd32(
	input wire [31:0] d_1,
	input wire [31:0] d_2,
	input wire ce,
	input wire clk,
	input wire clr,
	output reg [31:0] q_1 
);
function [31:0]fun_1;
	input [31:0] d_1;
	input [31:0] d_2;
begin
	fun_1 <= d_1 & d_2;                     //函数中不应使用非阻塞赋值
end	
endfunction

always@(posedge clk)
  begin
	if(clr)
		begin
		q_1 <= 32'h00000000;
		end	 
	else 
		if(ce)
			begin
			q_1 <= fun_1(d_1,d_2);
			end
		else 
			q_1 <= 32'hffffffff;
  end 	
endmodule

