module fd32(
	input wire d_1,
	input wire sel,
	input wire clk,
	input wire clr,
	input wire g_1,
	output reg q_1 
);

wire c_g;
reg mux_out;

assign c_g = clk & g_1;

always@(sel or d_1 or c_g)
	begin
		if(sel)
			mux_out = d_1;
		else 
			mux_out = c_g;   //违反
	end

